import React, { useContext } from 'react';
import { LanguageContext } from '../contexts/LanguageContext';
import { ReportInfo, ValidationErrors } from '../types';

interface ReportInfoFormProps {
    reportInfo: ReportInfo;
    setReportInfo: React.Dispatch<React.SetStateAction<ReportInfo>>;
    validationErrors: ValidationErrors;
}

const ReportInfoForm: React.FC<ReportInfoFormProps> = ({ reportInfo, setReportInfo, validationErrors }) => {
    const { t } = useContext(LanguageContext);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setReportInfo(prev => ({ ...prev, [name]: value }));
    };

    const dormitoryOptions = [
        '移工宿舍1(臨江路)',
        '移工宿舍2(中山路二段)',
        '移工宿舍3(苑裡山柑)',
    ];

    const renderInput = (name: keyof ReportInfo, type: string = 'text') => {
        const isInvalid = validationErrors[name];

        if (name === 'dormitoryName') {
            return (
                <div>
                    <label htmlFor={name} className="block text-sm font-medium text-gray-700 mb-1">{t(name as any)}</label>
                    <select
                        id={name}
                        name={name}
                        value={reportInfo[name]}
                        onChange={handleChange}
                        className={`w-full px-3 py-2 border rounded-md shadow-sm focus:outline-none focus:ring-2 appearance-none bg-white ${
                            isInvalid
                                ? 'border-red-500 bg-red-50 focus:ring-red-500 focus:border-red-500'
                                : 'border-gray-300 focus:ring-blue-500 focus:border-blue-500'
                        }`}
                    >
                        <option value="">-- {t('selectDormitory')} --</option>
                        {dormitoryOptions.map(opt => (
                            <option key={opt} value={opt}>{opt}</option>
                        ))}
                    </select>
                </div>
            );
        }

        return (
            <div>
                <label htmlFor={name} className="block text-sm font-medium text-gray-700 mb-1">{t(name as any)}</label>
                <input
                    type={type}
                    id={name}
                    name={name}
                    value={reportInfo[name]}
                    onChange={handleChange}
                    className={`w-full px-3 py-2 border rounded-md shadow-sm focus:outline-none focus:ring-2 ${
                        isInvalid
                            ? 'border-red-500 bg-red-50 focus:ring-red-500 focus:border-red-500'
                            : 'border-gray-300 focus:ring-blue-500 focus:border-blue-500'
                    }`}
                />
            </div>
        );
    };

    return (
        <div className="bg-white shadow-md rounded-xl p-6">
            <h2 className="text-xl font-bold text-gray-800 mb-4">{t('reportInfoTitle')}</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {renderInput('checkDate', 'date')}
                {renderInput('inspector')}
                {renderInput('dormitoryName')}
                {renderInput('dormitoryManagement')}
            </div>
        </div>
    );
};

export default ReportInfoForm;

export type LanguageCode = 'zh-TW' | 'en' | 'vi' | 'id' | 'th' | 'ms';

export interface ReportInfo {
  reportNo?: string;
  checkDate: string;
  inspector: string;
  dormitoryName: string;
  dormitoryManagement: string;
}

export interface ChecklistItemAnswer {
  status: 'Y' | 'N' | null;
  remarks: string;
  correctiveAction: string;
  responsiblePerson: string;
  targetDate: string;
  actionStatus: string;
}

export type ChecklistAnswers = Record<string, ChecklistItemAnswer>;

export type ValidationErrors = Record<string, boolean>;

export interface GeneratedReport {
  reportInfo: ReportInfo;
  checklistAnswers: ChecklistAnswers;
  photos: string[];
}

import React, { useContext, useRef } from 'react';
import { LanguageContext } from '../contexts/LanguageContext';
import { FaCamera, FaTrashAlt, FaPlus } from 'react-icons/fa';

interface ImageUploadProps {
    photos: string[];
    setPhotos: React.Dispatch<React.SetStateAction<string[]>>;
}

const ImageUpload: React.FC<ImageUploadProps> = ({ photos, setPhotos }) => {
    const { t } = useContext(LanguageContext);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = Array.from(e.target.files || []);
        if (files.length === 0) return;

        // Limit to 6 photos total
        const remainingSlots = 6 - photos.length;
        const filesToProcess = files.slice(0, remainingSlots);

        filesToProcess.forEach(file => {
            const reader = new FileReader();
            reader.onloadend = () => {
                const base64String = reader.result as string;
                setPhotos(prev => [...prev, base64String]);
            };
            reader.readAsDataURL(file);
        });

        // Reset input so the same file can be uploaded again if deleted
        if (fileInputRef.current) {
            fileInputRef.current.value = '';
        }
    };

    const removePhoto = (index: number) => {
        setPhotos(prev => prev.filter((_, i) => i !== index));
    };

    const triggerFileInput = () => {
        fileInputRef.current?.click();
    };

    return (
        <div className="bg-white shadow-md rounded-xl p-6">
            <h2 className="text-xl font-bold text-gray-800 mb-4 flex items-center">
                <FaCamera className="mr-2 text-blue-600" />
                {t('addPhotos')}
            </h2>

            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-4">
                {photos.map((photo, index) => (
                    <div key={index} className="relative group aspect-square rounded-lg overflow-hidden border border-gray-200 bg-gray-50">
                        <img 
                            src={photo} 
                            alt={`Attachment ${index + 1}`} 
                            className="w-full h-full object-cover"
                        />
                        <button
                            onClick={() => removePhoto(index)}
                            className="absolute top-1 right-1 bg-red-500 text-white p-1.5 rounded-full opacity-0 group-hover:opacity-100 transition-opacity duration-200 shadow-lg"
                            title={t('deletePhoto')}
                        >
                            <FaTrashAlt size={12} />
                        </button>
                    </div>
                ))}

                {photos.length < 6 && (
                    <button
                        onClick={triggerFileInput}
                        className="aspect-square flex flex-col items-center justify-center border-2 border-dashed border-gray-300 rounded-lg bg-gray-50 hover:bg-gray-100 hover:border-blue-400 transition-colors duration-200 group"
                    >
                        <FaPlus className="text-gray-400 group-hover:text-blue-500 mb-2" size={24} />
                        <span className="text-xs text-gray-500 group-hover:text-blue-600 text-center px-2">
                            {t('uploadHint')}
                        </span>
                        <input
                            type="file"
                            ref={fileInputRef}
                            onChange={handleFileChange}
                            accept="image/*"
                            multiple
                            className="hidden"
                        />
                    </button>
                )}
            </div>
        </div>
    );
};

export default ImageUpload;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Language, translations, Translation } from './constants/translations';
import { checklistData, ChecklistCategory } from './constants/checklistData';
import { ReportInfo, ChecklistAnswers, ValidationErrors, GeneratedReport, LanguageCode } from './types';
import LanguageSelector from './components/LanguageSelector';
import ReportInfoForm from './components/ReportInfoForm';
import Checklist from './components/Checklist';
import ImageUpload from './components/ImageUpload';
import ReportPreview from './components/ReportPreview';
import ValidationErrorModal from './components/ValidationErrorModal';
import { FaFileSignature, FaDownload } from 'react-icons/fa';
import { LanguageContext } from './contexts/LanguageContext';

declare global {
  interface Window {
    jspdf: any;
    html2canvas: any;
  }
}

const App: React.FC = () => {
  const [language, setLanguage] = useState<LanguageCode>('zh-TW');

  const getInitialReportInfo = (): ReportInfo => ({
    checkDate: new Date().toISOString().split('T')[0],
    inspector: '',
    dormitoryName: '',
    dormitoryManagement: '',
  });

  const getInitialChecklistAnswers = (): ChecklistAnswers => {
    const answers: ChecklistAnswers = {};
    checklistData.forEach(category => {
      category.items.forEach(item => {
        answers[item.id] = {
          status: null,
          remarks: '',
          correctiveAction: '',
          responsiblePerson: '',
          targetDate: '',
          actionStatus: 'pending',
        };
      });
    });
    return answers;
  };

  const [reportInfo, setReportInfo] = useState<ReportInfo>(getInitialReportInfo);
  const [checklistAnswers, setChecklistAnswers] = useState<ChecklistAnswers>(getInitialChecklistAnswers);
  const [photos, setPhotos] = useState<string[]>([]);
  const [validationErrors, setValidationErrors] = useState<ValidationErrors>({});
  const [showErrorModal, setShowErrorModal] = useState<boolean>(false);
  const [errorMessages, setErrorMessages] = useState<string[]>([]);
  const [generatedReport, setGeneratedReport] = useState<GeneratedReport | null>(null);
  const [isDownloading, setIsDownloading] = useState<boolean>(false);

  const reportPreviewRef = useRef<HTMLDivElement>(null);

  const t = useCallback((key: keyof Translation, replacements?: Record<string, string | number>): string => {
    const applyReplacements = (text: string): string => {
        if (!replacements) return text;
        let result = text;
        for (const placeholder in replacements) {
            const regex = new RegExp(`\\{${placeholder}\\}`, 'g');
            result = result.replace(regex, String(replacements[placeholder]));
        }
        return result;
    };

    const selectedLangText = applyReplacements(translations[language][key] || String(key));
    if (language === 'zh-TW') return selectedLangText;

    const chineseText = applyReplacements(translations['zh-TW'][key] || String(key));
    if (selectedLangText === chineseText) return selectedLangText;

    return `${selectedLangText} (${chineseText})`;
  }, [language]);

  const handleValidation = (): string[] => {
    const errors: string[] = [];
    const newValidationErrors: ValidationErrors = {};

    Object.keys(reportInfo).forEach(key => {
        const fieldKey = key as keyof ReportInfo;
        if (fieldKey !== 'reportNo' && !reportInfo[fieldKey]) {
            errors.push(t(fieldKey as keyof Translation));
            newValidationErrors[fieldKey] = true;
        }
    });

    Object.keys(checklistAnswers).forEach(itemId => {
        const item = checklistAnswers[itemId];
        if (item.status === null) {
            errors.push(`${t('checklistTitle')} (${itemId}): ${t('status')}`);
            newValidationErrors[itemId] = true;
        } else if (item.status === 'N') {
            if (!item.correctiveAction) {
                errors.push(`${t('checklistTitle')} (${itemId}): ${t('correctiveAction')}`);
                newValidationErrors[`${itemId}-correctiveAction`] = true;
            }
            if (!item.responsiblePerson) {
                errors.push(`${t('checklistTitle')} (${itemId}): ${t('responsiblePerson')}`);
                newValidationErrors[`${itemId}-responsiblePerson`] = true;
            }
            if (!item.targetDate) {
                errors.push(`${t('checklistTitle')} (${itemId}): ${t('targetDate')}`);
                newValidationErrors[`${itemId}-targetDate`] = true;
            }
        }
    });

    setValidationErrors(newValidationErrors);
    return errors;
  }

  const handleGenerateReport = () => {
    const messages = handleValidation();
    if (messages.length > 0) {
        setErrorMessages(messages);
        setShowErrorModal(true);
        setGeneratedReport(null);
    } else {
        setErrorMessages([]);
        setShowErrorModal(false);
        const reportNumber = `${reportInfo.checkDate.replace(/-/g, '')}-DORM-001`;
        const report: GeneratedReport = {
            reportInfo: { ...reportInfo, reportNo: reportNumber },
            checklistAnswers: { ...checklistAnswers },
            photos: [...photos],
        };
        setGeneratedReport(report);
    }
  };

  const handleDownloadReport = async () => {
    if (!reportPreviewRef.current || typeof window.html2canvas === 'undefined' || typeof window.jspdf === 'undefined') {
        console.error("PDF generation libraries not loaded.");
        alert("PDF generation libraries not loaded. Please try again in a moment.");
        return;
    }
    setIsDownloading(true);

    try {
        const canvas = await window.html2canvas(reportPreviewRef.current, {
            scale: 2,
            useCORS: true, 
        });
        const imgData = canvas.toDataURL('image/png');

        const { jsPDF } = window.jspdf;
        const pdf = new jsPDF({
            orientation: 'p',
            unit: 'mm',
            format: 'a4',
        });

        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = pdf.internal.pageSize.getHeight();
        const canvasWidth = canvas.width;
        const canvasHeight = canvas.height;
        const canvasAspectRatio = canvasWidth / canvasHeight;

        let imgWidth = pdfWidth;
        let imgHeight = imgWidth / canvasAspectRatio;

        let heightLeft = imgHeight;
        let position = 0;

        pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
        heightLeft -= pdfHeight;

        while (heightLeft > 0) {
            position = -heightLeft;
            pdf.addPage();
            pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
            heightLeft -= pdfHeight;
        }

        pdf.save(`dormitory-assessment-report-${reportInfo.checkDate || 'report'}.pdf`);
    } catch (error) {
        console.error("Error generating PDF:", error);
        alert("Sorry, there was an error generating the PDF.");
    } finally {
        setIsDownloading(false);
    }
  };

  useEffect(() => {
    if (generatedReport) {
      reportPreviewRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [generatedReport]);

  return (
    <LanguageContext.Provider value={{ language, setLanguage, t }}>
      <div className="container mx-auto p-4 sm:p-6 md:p-8 font-sans">
        <header className="bg-white shadow-md rounded-xl p-6 mb-8">
          <div className="flex flex-col md:flex-row justify-between items-center space-y-4 md:space-y-0">
            <div className="flex items-center space-x-4">
               <FaFileSignature className="text-4xl text-blue-600" />
               <div className="text-center md:text-left">
                  <h1 className="text-2xl md:text-3xl font-bold text-gray-800">{t('title')}</h1>
                  <p className="text-gray-500">{t('subtitle')}</p>
                </div>
            </div>
            <LanguageSelector />
          </div>
        </header>

        <main className="space-y-8">
          <ReportInfoForm
            reportInfo={reportInfo}
            setReportInfo={setReportInfo}
            validationErrors={validationErrors}
          />
          <Checklist
            checklistAnswers={checklistAnswers}
            setChecklistAnswers={setChecklistAnswers}
            validationErrors={validationErrors}
          />
          <ImageUpload
            photos={photos}
            setPhotos={setPhotos}
          />

          <div className="flex justify-center">
            <button
              onClick={handleGenerateReport}
              className="bg-blue-600 text-white font-bold py-3 px-8 rounded-lg hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-opacity-50 transition-transform transform hover:scale-105 w-full sm:w-auto"
            >
              {t('generateReportButton')}
            </button>
          </div>
        </main>

        {generatedReport && (
          <div className="mt-12">
            <div className="flex justify-end mb-4 space-x-2">
                 <button
                  onClick={handleDownloadReport}
                  disabled={isDownloading}
                  className="bg-green-500 text-white font-bold py-2 px-6 rounded-lg hover:bg-green-600 focus:outline-none focus:ring-2 focus:ring-green-400 focus:ring-opacity-50 transition-transform transform hover:scale-105 disabled:bg-gray-400 disabled:cursor-not-allowed flex items-center space-x-2"
                >
                  {isDownloading ? (
                    <>
                      <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                      </svg>
                      <span>{t('downloading')}</span>
                    </>
                  ) : (
                    <>
                      <FaDownload />
                      <span>{t('downloadReportButton')}</span>
                    </>
                  )}
                </button>
            </div>

            <div ref={reportPreviewRef}>
              <ReportPreview report={generatedReport} />
            </div>
          </div>
        )}

        {showErrorModal && (
          <ValidationErrorModal onClose={() => setShowErrorModal(false)} errorFields={errorMessages} />
        )}
      </div>
    </LanguageContext.Provider>
  );
};

export default App;

import React, { useContext } from 'react';
import { LanguageContext } from '../contexts/LanguageContext';
import { GeneratedReport } from '../types';
import { checklistData } from '../constants/checklistData';

interface ReportPreviewProps {
    report: GeneratedReport;
}

const ReportPreview: React.FC<ReportPreviewProps> = ({ report }) => {
    const { t } = useContext(LanguageContext);
    const { reportInfo, checklistAnswers, photos } = report;

    const nonCompliantItems = Object.keys(checklistAnswers).filter(key => checklistAnswers[key].status === 'N');

    const getItemDetails = (itemId: string) => {
        for (const category of checklistData) {
            const item = category.items.find(i => i.id === itemId);
            if (item) {
                return {
                    category: t(category.key),
                    description: t(item.id as any)
                };
            }
        }
        return { category: '', description: '' };
    };

    const tableHeaderClass = "px-3 sm:px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider bg-gray-50";
    const tableCellClass = "px-3 sm:px-4 py-4 text-sm text-gray-800";
    const tableRowClass = "border-b border-gray-200";

    return (
        <div className="bg-white shadow-lg rounded-xl p-4 sm:p-6 md:p-10 border border-gray-200 font-sans">
            <header className="text-center mb-10">
                <h2 className="text-2xl md:text-3xl font-bold text-gray-800">{t('reportTemplateTitle')}</h2>
            </header>

            {/* Basic Info */}
            <section className="mb-8 text-sm">
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-8 gap-y-2">
                    <p><strong className="font-semibold text-gray-600">{t('reportNo')}:</strong> {reportInfo.reportNo}</p>
                    <p><strong className="font-semibold text-gray-600">{t('checkDate')}:</strong> {reportInfo.checkDate}</p>
                    <p><strong className="font-semibold text-gray-600">{t('dormitoryName')}:</strong> {reportInfo.dormitoryName}</p>
                    <p><strong className="font-semibold text-gray-600">{t('inspector')}:</strong> {reportInfo.inspector}</p>
                    <p><strong className="font-semibold text-gray-600">{t('dormitoryManagement')}:</strong> {reportInfo.dormitoryManagement}</p>
                </div>
            </section>
            <hr className="my-8" />

            {/* 1. Overview */}
            <section className="mb-8">
                <h3 className="text-xl font-bold text-gray-800 mb-3">{t('overviewSectionTitle')}</h3>
                <p className="text-gray-700 text-sm leading-relaxed">{t('overviewText')}</p>
            </section>

            {/* 2. Findings Table */}
            <section className="mb-8">
                <h3 className="text-xl font-bold text-gray-800 mb-3">{t('findingsSectionTitle')}</h3>
                <p className="text-gray-700 text-sm mb-4">{t('findingsIntro', { count: nonCompliantItems.length })}</p>
                <div className="overflow-x-auto border border-gray-200 rounded-lg">
                    <table className="min-w-full divide-y divide-gray-200">
                        <thead>
                            <tr>
                                <th className={tableHeaderClass}>No.</th>
                                <th className={tableHeaderClass}>{t('category')}</th>
                                <th className={tableHeaderClass}>{t('findingItem')}</th>
                                <th className={tableHeaderClass}>{t('detailedDescription')}</th>
                                <th className={tableHeaderClass}>{t('complianceStatus')}</th>
                            </tr>
                        </thead>
                        <tbody className="bg-white divide-y divide-gray-200">
                            {nonCompliantItems.length > 0 ? (
                                nonCompliantItems.map((itemId, index) => {
                                    const details = getItemDetails(itemId);
                                    return (
                                        <tr key={itemId} className={tableRowClass}>
                                            <td className={tableCellClass}>{index + 1}</td>
                                            <td className={tableCellClass}>{details.category}</td>
                                            <td className={`${tableCellClass} font-semibold whitespace-normal w-1/3`}>{details.description}</td>
                                            <td className={`${tableCellClass} whitespace-normal`}>{checklistAnswers[itemId].remarks || '-'}</td>
                                            <td className={`${tableCellClass} text-red-600 font-bold`}>{t('no')}</td>
                                        </tr>
                                    );
                                })
                            ) : (
                                <tr className={tableRowClass}>
                                    <td className={tableCellClass}>1</td>
                                    <td className={tableCellClass}>-</td>
                                    <td className={tableCellClass}>{t('noFindingsItem')}</td>
                                    <td className={tableCellClass}>{t('noFindingsDescription')}</td>
                                    <td className={`${tableCellClass} text-green-600 font-bold`}>{t('statusCompliant')}</td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </section>

            {/* 3. Action Plan Table */}
            <section className="mb-8">
                <h3 className="text-xl font-bold text-gray-800 mb-3">{t('actionPlanSectionTitle')}</h3>
                 <div className="overflow-x-auto border border-gray-200 rounded-lg">
                    <table className="min-w-full divide-y divide-gray-200">
                        <thead >
                            <tr>
                                <th className={tableHeaderClass}>No.</th>
                                <th className={tableHeaderClass}>{t('findingItem')}</th>
                                <th className={tableHeaderClass}>{t('correctiveAction')}</th>
                                <th className={tableHeaderClass}>{t('responsiblePerson')}</th>
                                <th className={tableHeaderClass}>{t('targetDate')}</th>
                                <th className={tableHeaderClass}>{t('actionStatus')}</th>
                            </tr>
                        </thead>
                        <tbody className="bg-white divide-y divide-gray-200">
                            {nonCompliantItems.length > 0 ? (
                                nonCompliantItems.map((itemId, index) => {
                                    const details = getItemDetails(itemId);
                                    return (
                                        <tr key={itemId} className={tableRowClass}>
                                            <td className={tableCellClass}>{index + 1}</td>
                                            <td className={`${tableCellClass} whitespace-normal w-1/4`}><span className="font-mono text-red-600">{itemId}:</span> {details.description}</td>
                                            <td className={`${tableCellClass} whitespace-normal`}>{checklistAnswers[itemId].correctiveAction}</td>
                                            <td className={tableCellClass}>{checklistAnswers[itemId].responsiblePerson}</td>
                                            <td className={tableCellClass}>{checklistAnswers[itemId].targetDate}</td>
                                            <td className={tableCellClass}><span className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-yellow-100 text-yellow-800">{t('statusPending')}</span></td>
                                        </tr>
                                    );
                                })
                            ) : (
                                <tr className={tableRowClass}>
                                    <td className={tableCellClass}>1</td>
                                    <td className={tableCellClass}>{t('noActionItem')}</td>
                                    <td className={tableCellClass}>{t('noActionRecommendation')}</td>
                                    <td className={tableCellClass}>{t('noActionResponsible')}</td>
                                    <td className={tableCellClass}>{t('noActionTargetDate')}</td>
                                    <td className={tableCellClass}><span className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-green-100 text-green-800">{t('noActionStatus')}</span></td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </section>

            {/* 4. Conclusion */}
            <section className="mb-8">
                <h3 className="text-xl font-bold text-gray-800 mb-3">{t('conclusionSectionTitle')}</h3>
                <p className="text-gray-700 text-sm leading-relaxed">
                    {nonCompliantItems.length > 0 ? t('conclusionTextNonCompliant') : t('conclusionTextCompliant')}
                </p>
            </section>

            {/* 5. Attachments */}
             <section>
                <h3 className="text-xl font-bold text-gray-800 mb-3">{t('attachmentsSectionTitle')}</h3>
                {photos.length > 0 ? (
                    <div className="grid grid-cols-2 gap-4 mt-4">
                        {photos.map((photo, index) => (
                            <div key={index} className="border border-gray-200 rounded-lg overflow-hidden">
                                <img src={photo} alt={`Site Photo ${index + 1}`} className="w-full h-48 object-cover" />
                                <div className="bg-gray-50 p-2 text-center text-xs text-gray-500 font-semibold border-t border-gray-200">
                                    {t('onSitePhotos')} - {index + 1}
                                </div>
                            </div>
                        ))}
                    </div>
                ) : (
                    <ul className="list-disc list-inside text-gray-700 text-sm space-y-1">
                        <li>{t('onSitePhotos')}</li>
                        <li>{t('workerInterviews')}</li>
                    </ul>
