import React, { useState, useContext } from 'react';
import { LanguageContext } from '../contexts/LanguageContext';
import { FaGoogleDrive, FaCheckCircle, FaExclamationCircle } from 'react-icons/fa';

interface GoogleDriveUploadProps {
    getPdfBlob: () => Promise<Blob | null>;
    fileName: string;
}

// 您指定的雲端硬碟資料夾 ID
const FOLDER_ID = '11_Bdd1tKHTAR-CJ79o-0ShE5VLB3objg';

// 注意：在正式環境中，您需要從 Google Cloud Console 申請 Client ID 並填入此處
const CLIENT_ID = 'YOUR_GOOGLE_CLIENT_ID.apps.googleusercontent.com';

const GoogleDriveUpload: React.FC<GoogleDriveUploadProps> = ({ getPdfBlob, fileName }) => {
    const { t } = useContext(LanguageContext);
    const [status, setStatus] = useState<'idle' | 'uploading' | 'success' | 'error'>('idle');

    const handleUpload = async () => {
        if (status === 'uploading') return;
        setStatus('uploading');

        try {
            // 1. 獲取 Google 授權 Token
            // 這裡使用 Google Identity Services 進行 Token 請求
            const tokenResponse = await new Promise<any>((resolve, reject) => {
                const client = (window as any).google.accounts.oauth2.initTokenClient({
                    client_id: CLIENT_ID,
                    scope: 'https://www.googleapis.com/auth/drive.file',
                    callback: (resp: any) => {
                        if (resp.error) reject(resp);
                        else resolve(resp);
                    },
                });
                client.requestAccessToken();
            });

            const accessToken = tokenResponse.access_token;

            // 2. 獲取 PDF Blob
            const blob = await getPdfBlob();
            if (!blob) throw new Error('Could not generate PDF');

            // 3. 準備 Multipart 上傳內容
            const metadata = {
                name: fileName,
                parents: [FOLDER_ID],
                mimeType: 'application/pdf',
            };

            const form = new FormData();
            form.append('metadata', new Blob([JSON.stringify(metadata)], { type: 'application/json' }));
            form.append('file', blob);

            // 4. 發送請求至 Google Drive API
            const response = await fetch('https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart', {
                method: 'POST',
                headers: {
                    Authorization: `Bearer ${accessToken}`,
                },
                body: form,
            });

            if (!response.ok) {
                const errorData = await response.json();
                console.error('Drive API Error:', errorData);
                throw new Error('Upload failed');
            }

            setStatus('success');
            setTimeout(() => setStatus('idle'), 5000);
        } catch (error) {
            console.error('Upload Error:', error);
            setStatus('error');
            setTimeout(() => setStatus('idle'), 5000);
        }
    };

    return (
        <button
            onClick={handleUpload}
            disabled={status === 'uploading'}
            className={`flex items-center space-x-2 font-bold py-2 px-6 rounded-lg transition-all transform hover:scale-105 shadow-md ${
                status === 'success' ? 'bg-green-100 text-green-700' : 
                status === 'error' ? 'bg-red-100 text-red-700' : 
                'bg-white text-blue-600 border border-blue-200 hover:bg-blue-50'
            }`}
        >
            {status === 'uploading' ? (
                <>
                    <svg className="animate-spin h-5 w-5 text-blue-600" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    <span>{t('uploading')}</span>
                </>
            ) : status === 'success' ? (
                <>
                    <FaCheckCircle className="text-xl" />
                    <span>{t('uploadSuccess')}</span>
                </>
            ) : status === 'error' ? (
                <>
                    <FaExclamationCircle className="text-xl" />
                    <span>{t('uploadError')}</span>
                </>
            ) : (
                <>
                    <FaGoogleDrive className="text-xl text-blue-500" />
                    <span>{t('uploadToDrive')}</span>
                </>
            )}
        </button>
    );
};

export default GoogleDriveUpload;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Language, translations, Translation } from './constants/translations';
import { checklistData, ChecklistCategory } from './constants/checklistData';
import { ReportInfo, ChecklistAnswers, ValidationErrors, GeneratedReport, LanguageCode } from './types';
import LanguageSelector from './components/LanguageSelector';
import ReportInfoForm from './components/ReportInfoForm';
import Checklist from './components/Checklist';
import ImageUpload from './components/ImageUpload';
import ReportPreview from './components/ReportPreview';
import GoogleDriveUpload from './components/GoogleDriveUpload';
import ValidationErrorModal from './components/ValidationErrorModal';
import { FaFileSignature, FaDownload } from 'react-icons/fa';
import { LanguageContext } from './contexts/LanguageContext';

declare global {
  interface Window {
    jspdf: any;
    html2canvas: any;
  }
}

const App: React.FC = () => {
  const [language, setLanguage] = useState<LanguageCode>('zh-TW');

  const getInitialReportInfo = (): ReportInfo => ({
    checkDate: new Date().toISOString().split('T')[0],
    inspector: '',
    dormitoryName: '',
    dormitoryManagement: '',
  });

  const getInitialChecklistAnswers = (): ChecklistAnswers => {
    const answers: ChecklistAnswers = {};
    checklistData.forEach(category => {
      category.items.forEach(item => {
        answers[item.id] = {
          status: null,
          remarks: '',
          correctiveAction: '',
          responsiblePerson: '',
          targetDate: '',
          actionStatus: 'pending',
        };
      });
    });
    return answers;
  };

  const [reportInfo, setReportInfo] = useState<ReportInfo>(getInitialReportInfo);
  const [checklistAnswers, setChecklistAnswers] = useState<ChecklistAnswers>(getInitialChecklistAnswers);
  const [photos, setPhotos] = useState<string[]>([]);
  const [validationErrors, setValidationErrors] = useState<ValidationErrors>({});
  const [showErrorModal, setShowErrorModal] = useState<boolean>(false);
  const [errorMessages, setErrorMessages] = useState<string[]>([]);
  const [generatedReport, setGeneratedReport] = useState<GeneratedReport | null>(null);
  const [isDownloading, setIsDownloading] = useState<boolean>(false);

  const reportPreviewRef = useRef<HTMLDivElement>(null);

  const t = useCallback((key: keyof Translation, replacements?: Record<string, string | number>): string => {
    const applyReplacements = (text: string): string => {
        if (!replacements) return text;
        let result = text;
        for (const placeholder in replacements) {
            const regex = new RegExp(`\\{${placeholder}\\}`, 'g');
            result = result.replace(regex, String(replacements[placeholder]));
        }
        return result;
    };

    const selectedLangText = applyReplacements(translations[language][key] || String(key));
    if (language === 'zh-TW') return selectedLangText;

    const chineseText = applyReplacements(translations['zh-TW'][key] || String(key));
    if (selectedLangText === chineseText) return selectedLangText;

    return `${selectedLangText} (${chineseText})`;
  }, [language]);

  const handleValidation = (): string[] => {
    const errors: string[] = [];
    const newValidationErrors: ValidationErrors = {};

    Object.keys(reportInfo).forEach(key => {
        const fieldKey = key as keyof ReportInfo;
        if (fieldKey !== 'reportNo' && !reportInfo[fieldKey]) {
            errors.push(t(fieldKey as keyof Translation));
            newValidationErrors[fieldKey] = true;
        }
    });

    Object.keys(checklistAnswers).forEach(itemId => {
        const item = checklistAnswers[itemId];
        if (item.status === null) {
            errors.push(`${t('checklistTitle')} (${itemId}): ${t('status')}`);
            newValidationErrors[itemId] = true;
        } else if (item.status === 'N') {
            if (!item.correctiveAction) {
                errors.push(`${t('checklistTitle')} (${itemId}): ${t('correctiveAction')}`);
                newValidationErrors[`${itemId}-correctiveAction`] = true;
            }
            if (!item.responsiblePerson) {
                errors.push(`${t('checklistTitle')} (${itemId}): ${t('responsiblePerson')}`);
                newValidationErrors[`${itemId}-responsiblePerson`] = true;
            }
            if (!item.targetDate) {
                errors.push(`${t('checklistTitle')} (${itemId}): ${t('targetDate')}`);
                newValidationErrors[`${itemId}-targetDate`] = true;
            }
        }
    });

    setValidationErrors(newValidationErrors);
    return errors;
  }

  const handleGenerateReport = () => {
    const messages = handleValidation();
    if (messages.length > 0) {
        setErrorMessages(messages);
        setShowErrorModal(true);
        setGeneratedReport(null);
    } else {
        setErrorMessages([]);
        setShowErrorModal(false);
        const reportNumber = `${reportInfo.checkDate.replace(/-/g, '')}-DORM-001`;
        const report: GeneratedReport = {
            reportInfo: { ...reportInfo, reportNo: reportNumber },
            checklistAnswers: { ...checklistAnswers },
            photos: [...photos],
        };
        setGeneratedReport(report);
    }
  };

  /**
   * Helper function to add canvas content to PDF with margins and multi-page support
   */
  const addCanvasToPdf = (pdf: any, canvas: HTMLCanvasElement, startsOnNewPage: boolean) => {
    const margin = 10; 
    const pdfWidth = pdf.internal.pageSize.getWidth();
    const pdfHeight = pdf.internal.pageSize.getHeight();

    const usableWidth = pdfWidth - (2 * margin);
    const usableHeight = pdfHeight - (2 * margin);

    const imgWidth = usableWidth;
    const imgHeight = imgWidth * (canvas.height / canvas.width);
    const imgData = canvas.toDataURL('image/png');

    let heightLeft = imgHeight;
    let sourceY = 0;
    let isFirstIteration = true;

    while (heightLeft > 0) {
      if (!isFirstIteration || startsOnNewPage) {
        pdf.addPage();
      }

      pdf.addImage(imgData, 'PNG', margin, margin - sourceY, imgWidth, imgHeight);

      pdf.setFillColor(255, 255, 255);
      pdf.rect(0, 0, pdfWidth, margin, 'F'); 
      pdf.rect(0, pdfHeight - margin, pdfWidth, margin, 'F'); 
      pdf.rect(0, 0, margin, pdfHeight, 'F'); 
      pdf.rect(pdfWidth - margin, 0, margin, pdfHeight, 'F'); 

      sourceY += usableHeight;
      heightLeft -= usableHeight;
      isFirstIteration = false;
    }
  };

  /**
   * 生成 PDF Blob 的共用邏輯，供下載與雲端上傳使用
   */
  const generatePdfBlob = async (): Promise<Blob | null> => {
    if (!reportPreviewRef.current || typeof window.html2canvas === 'undefined' || typeof window.jspdf === 'undefined') {
        return null;
    }

    const { jsPDF } = window.jspdf;
    const pdf = new jsPDF({
        orientation: 'p',
        unit: 'mm',
        format: 'a4',
    });

    const mainContentEl = document.getElementById('report-main-content');
    const attachmentsEl = document.getElementById('report-attachments-section');

    if (generatedReport && generatedReport.photos.length > 0 && mainContentEl && attachmentsEl) {
        const mainCanvas = await window.html2canvas(mainContentEl, { scale: 2, useCORS: true });
        addCanvasToPdf(pdf, mainCanvas, false);

        const attachmentCanvas = await window.html2canvas(attachmentsEl, { scale: 2, useCORS: true });
        addCanvasToPdf(pdf, attachmentCanvas, true);
    } else {
        const canvas = await window.html2canvas(reportPreviewRef.current, { scale: 2, useCORS: true });
        addCanvasToPdf(pdf, canvas, false);
    }

    return pdf.output('blob');
  };

  const handleDownloadReport = async () => {
    setIsDownloading(true);
    try {
        const blob = await generatePdfBlob();
        if (blob) {
            const url = URL.createObjectURL(blob);
            const link = document.createElement('a');
            link.href = url;
            link.download = `dormitory-assessment-report-${reportInfo.checkDate || 'report'}.pdf`;
            link.click();
            URL.revokeObjectURL(url);
        } else {
            alert("PDF generation error.");
        }
    } catch (error) {
        console.error("Download Error:", error);
    } finally {
        setIsDownloading(false);
    }
  };

  useEffect(() => {
    if (generatedReport) {
      reportPreviewRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [generatedReport]);

  const pdfFileName = `dormitory-report-${reportInfo.dormitoryName}-${reportInfo.checkDate}.pdf`;

  return (
    <LanguageContext.Provider value={{ language, setLanguage, t }}>
      <div className="container mx-auto p-4 sm:p-6 md:p-8 font-sans">
        <header className="bg-white shadow-md rounded-xl p-6 mb-8">
          <div className="flex flex-col md:flex-row justify-between items-center space-y-4 md:space-y-0">
            <div className="flex items-center space-x-4">
               <FaFileSignature className="text-4xl text-blue-600" />
               <div className="text-center md:text-left">
                  <h1 className="text-2xl md:text-3xl font-bold text-gray-800">{t('title')}</h1>
                  <p className="text-gray-500">{t('subtitle')}</p>
                </div>
            </div>
            <LanguageSelector />
          </div>
        </header>

        <main className="space-y-8">
          <ReportInfoForm
            reportInfo={reportInfo}
            setReportInfo={setReportInfo}
            validationErrors={validationErrors}
          />
          <Checklist
            checklistAnswers={checklistAnswers}
            setChecklistAnswers={setChecklistAnswers}
            validationErrors={validationErrors}
          />
          <ImageUpload
            photos={photos}
            setPhotos={setPhotos}
          />

          <div className="flex justify-center">
            <button
              onClick={handleGenerateReport}
              className="bg-blue-600 text-white font-bold py-3 px-8 rounded-lg hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-opacity-50 transition-transform transform hover:scale-105 w-full sm:w-auto"
            >
              {t('generateReportButton')}
            </button>
          </div>
        </main>

        {generatedReport && (
          <div className="mt-12">
            <div className="flex flex-col sm:flex-row justify-end mb-4 space-y-2 sm:space-y-0 sm:space-x-4">
                {/* 雲端上傳按鈕 */}
                <GoogleDriveUpload 
                    getPdfBlob={generatePdfBlob} 
                    fileName={pdfFileName} 
                />

                <button
                  onClick={handleDownloadReport}
                  disabled={isDownloading}
                  className="bg-green-500 text-white font-bold py-2 px-6 rounded-lg hover:bg-green-600 focus:outline-none focus:ring-2 focus:ring-green-400 focus:ring-opacity-50 transition-transform transform hover:scale-105 disabled:bg-gray-400 disabled:cursor-not-allowed flex items-center justify-center space-x-2 shadow-md"
                >
                  {isDownloading ? (
                    <>
                      <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                      </svg>
                      <span>{t('downloading')}</span>
                    </>
                  ) : (
                    <>
                      <FaDownload />
                      <span>{t('downloadReportButton')}</span>
                    </>
                  )}
                </button>
            </div>

            <div ref={reportPreviewRef}>
              <ReportPreview report={generatedReport} />
            </div>
          </div>
        )}

        {showErrorModal && (
          <ValidationErrorModal onClose={() => setShowErrorModal(false)} errorFields={errorMessages} />
        )}
      </div>
    </LanguageContext.Provider>
  );
};

export default App;

import React, { useContext, useRef } from 'react';
import { LanguageContext } from '../contexts/LanguageContext';
import { FaSave, FaUpload, FaTrashAlt, FaInfoCircle } from 'react-icons/fa';
import { ReportInfo, ChecklistAnswers } from '../types';

interface DataManagementProps {
    reportInfo: ReportInfo;
    checklistAnswers: ChecklistAnswers;
    photos: string[];
    onRestore: (data: { reportInfo: ReportInfo, checklistAnswers: ChecklistAnswers, photos: string[] }) => void;
    onClear: () => void;
}

const DataManagement: React.FC<DataManagementProps> = ({ reportInfo, checklistAnswers, photos, onRestore, onClear }) => {
    const { t } = useContext(LanguageContext);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleExport = () => {
        const data = {
            reportInfo,
            checklistAnswers,
            photos,
            exportedAt: new Date().toISOString()
        };
        const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        const fileName = `dorm-assessment-${reportInfo.dormitoryName || 'backup'}-${new Date().toISOString().split('T')[0]}.json`;
        link.download = fileName;
        link.click();
        URL.revokeObjectURL(url);
    };

    const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const data = JSON.parse(event.target?.result as string);
                if (data.reportInfo && data.checklistAnswers) {
                    onRestore({
                        reportInfo: data.reportInfo,
                        checklistAnswers: data.checklistAnswers,
                        photos: data.photos || []
                    });
                } else {
                    throw new Error('Invalid format');
                }
            } catch (err) {
                alert('導入失敗，請確保檔案格式正確。');
            }
        };
        reader.readAsText(file);
        if (fileInputRef.current) fileInputRef.current.value = '';
    };

    const confirmClear = () => {
        if (window.confirm('確定要清空所有已填寫的內容嗎？此動作無法復原。')) {
            onClear();
        }
    };

    return (
        <div className="bg-white shadow-md rounded-xl p-6 border-l-4 border-blue-500 mb-8">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-4 space-y-4 md:space-y-0">
                <div>
                    <h2 className="text-xl font-bold text-gray-800 flex items-center">
                        <FaSave className="mr-2 text-blue-600" />
                        資料備份與還原
                    </h2>
                    <p className="text-xs text-gray-500 mt-1 flex items-center">
                        <FaInfoCircle className="mr-1" />
                        提示：您可以下載 JSON 備份檔，或是手動儲存至雲端。
                    </p>
                </div>

                <div className="flex flex-wrap gap-2">
                    <button
                        onClick={handleExport}
                        className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center transition-colors shadow-sm"
                    >
                        <FaSave className="mr-2" />
                        匯出 JSON 備份
                    </button>

                    <button
                        onClick={() => fileInputRef.current?.click()}
                        className="bg-gray-100 hover:bg-gray-200 text-gray-700 px-4 py-2 rounded-lg text-sm font-bold flex items-center transition-colors border border-gray-300"
                    >
                        <FaUpload className="mr-2" />
                        導入備份
                    </button>

                    <button
                        onClick={confirmClear}
                        className="bg-red-50 hover:bg-red-100 text-red-600 px-4 py-2 rounded-lg text-sm font-bold flex items-center transition-colors border border-red-200"
                    >
                        <FaTrashAlt className="mr-2" />
                        清空資料
                    </button>
                </div>
            </div>
            <input type="file" ref={fileInputRef} onChange={handleImport} accept=".json" className="hidden" />
        </div>
    );
};

export default DataManagement;

import React, { useState, useContext } from 'react';
import { LanguageContext } from '../contexts/LanguageContext';
import { FaGoogleDrive, FaCheckCircle, FaExclamationCircle } from 'react-icons/fa';

interface GoogleDriveUploadProps {
    getPdfBlob: () => Promise<Blob | null>;
    fileName: string;
}

// 您指定的雲端硬碟資料夾 ID
const FOLDER_ID = '11_Bdd1tKHTAR-CJ79o-0ShE5VLB3objg';

// 重要：請將此處替換為您從 Google Cloud Console 獲得的真實 Client ID
// 如果沒有替換，點擊時會出現 400 錯誤。
const CLIENT_ID = 'YOUR_GOOGLE_CLIENT_ID.apps.googleusercontent.com';

const GoogleDriveUpload: React.FC<GoogleDriveUploadProps> = ({ getPdfBlob, fileName }) => {
    const { t } = useContext(LanguageContext);
    const [status, setStatus] = useState<'idle' | 'uploading' | 'success' | 'error'>('idle');
    const [errorMessage, setErrorMessage] = useState<string>('');

    const handleUpload = async () => {
        if (CLIENT_ID.startsWith('YOUR_GOOGLE_CLIENT_ID')) {
            alert('尚未設定有效的 Google Client ID。請在程式碼中填入您的憑證資訊以啟用上傳功能。');
            return;
        }

        if (status === 'uploading') return;
        setStatus('uploading');
        setErrorMessage('');

        try {
            // 1. 獲取 Google 授權 Token
            const tokenResponse = await new Promise<any>((resolve, reject) => {
                try {
                    const client = (window as any).google.accounts.oauth2.initTokenClient({
                        client_id: CLIENT_ID,
                        scope: 'https://www.googleapis.com/auth/drive.file',
                        callback: (resp: any) => {
                            if (resp.error) reject(resp);
                            else resolve(resp);
                        },
                    });
                    client.requestAccessToken();
                } catch (e) {
                    reject(e);
                }
            });

            const accessToken = tokenResponse.access_token;

            // 2. 獲取 PDF Blob
            const blob = await getPdfBlob();
            if (!blob) throw new Error('Could not generate PDF');

            // 3. 準備 Multipart 上傳內容 (Metadata + File)
            const metadata = {
                name: fileName,
                parents: [FOLDER_ID],
                mimeType: 'application/pdf',
            };

            const boundary = '-------314159265358979323846';
            const delimiter = "\r\n--" + boundary + "\r\n";
            const close_delim = "\r\n--" + boundary + "--";

            const reader = new FileReader();
            reader.readAsBinaryString(blob);
            reader.onload = async () => {
                const contentType = 'application/pdf';
                const metadataPart = 'Content-Type: application/json\r\n\r\n' + JSON.stringify(metadata);
                const filePart = 'Content-Type: ' + contentType + '\r\n' + 'Content-Transfer-Encoding: base64\r\n\r\n' + btoa(reader.result as string);

                const multipartRequestBody =
                    delimiter +
                    metadataPart +
                    delimiter +
                    filePart +
                    close_delim;

                // 4. 發送請求至 Google Drive API
                const response = await fetch('https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart', {
                    method: 'POST',
                    headers: {
                        Authorization: `Bearer ${accessToken}`,
                        'Content-Type': 'multipart/related; boundary="' + boundary + '"',
                    },
                    body: multipartRequestBody,
                });

                if (!response.ok) {
                    const errorData = await response.json();
                    throw new Error(errorData.error?.message || 'Upload failed');
                }

                setStatus('success');
                setTimeout(() => setStatus('idle'), 5000);
            };
        } catch (error: any) {
            console.error('Upload Error:', error);
            setErrorMessage(error.message || 'Error');
            setStatus('error');
            setTimeout(() => setStatus('idle'), 5000);
        }
    };

    return (
        <div className="flex flex-col items-end">
            <button
                onClick={handleUpload}
                disabled={status === 'uploading'}
                className={`flex items-center space-x-2 font-bold py-2 px-6 rounded-lg transition-all transform hover:scale-105 shadow-md ${
                    status === 'success' ? 'bg-green-100 text-green-700' : 
                    status === 'error' ? 'bg-red-100 text-red-700' : 
                    'bg-white text-blue-600 border border-blue-200 hover:bg-blue-50'
                }`}
            >
                {status === 'uploading' ? (
                    <>
                        <svg className="animate-spin h-5 w-5 text-blue-600" viewBox="0 0 24 24">
                            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                        </svg>
                        <span>{t('uploading')}</span>
                    </>
                ) : status === 'success' ? (
