}

/**
 * [針對 400 錯誤與「已封鎖存取權」的終極解決方案]
 * 
 * 根據您的 Console 截圖，您的狀態是「實際運作中 (Production)」。
 * 因為應用程式未經過 Google 官方驗證，所以會被封鎖。
 * 
 * 請執行以下步驟：
 * 1. 點擊 Google Cloud Console 中的 【返回測試應用程式】。
 * 2. 頁面下方會出現 【測試使用者 (Test users)】 區域。
 * 3. 點擊 【+ ADD USERS】 並加入：cb_esg@carbotec.com.tw
 */
const FOLDER_ID = '1pPM8zepZlfHYu5-IVcP7P_4vOsw5xZWi';
const CLIENT_ID = '107079139052-ebc9550lab5vlh4hg337m7h54lpqgpek.apps.googleusercontent.com';

const GoogleDriveUpload: React.FC<GoogleDriveUploadProps> = ({ getPdfBlob, fileName }) => {
    const { t } = useContext(LanguageContext);
    const [status, setStatus] = useState<'idle' | 'uploading' | 'success' | 'error'>('idle');
    const [errorMessage, setErrorMessage] = useState<string>('');
    const [showFixGuide, setShowFixGuide] = useState(false);

    const handleUpload = async () => {
        if (status === 'uploading') return;
        setStatus('uploading');
        setErrorMessage('');
        setShowFixGuide(false);

        try {
            const tokenResponse = await new Promise<any>((resolve, reject) => {
                try {
                    if (!(window as any).google?.accounts?.oauth2) {
                        throw new Error('Google SDK 載入異常');
                    }

                    const client = (window as any).google.accounts.oauth2.initTokenClient({
                        client_id: CLIENT_ID,
                        scope: 'https://www.googleapis.com/auth/drive.file',
                        callback: (resp: any) => {
                            if (resp.error) reject(resp);
                            else resolve(resp);
                        },
                        error_callback: (err: any) => reject(err)
                    });

                    client.requestAccessToken({ prompt: 'select_account' });
                } catch (e) {
                    reject(e);
                }
            });

            const accessToken = tokenResponse.access_token;
            if (!accessToken) throw new Error('授權失敗');

            const blob = await getPdfBlob();
            if (!blob) throw new Error('PDF 生成失敗');

            const metadata = {
                name: fileName,
                parents: [FOLDER_ID],
                mimeType: 'application/pdf',
            };

            const boundary = '-------314159265358979323846';
            const delimiter = "\r\n--" + boundary + "\r\n";
            const close_delim = "\r\n--" + boundary + "--";

            const reader = new FileReader();
            reader.readAsArrayBuffer(blob);

            await new Promise((resolve, reject) => {
                reader.onload = async () => {
                    try {
                        const uint8Array = new Uint8Array(reader.result as ArrayBuffer);
                        let binary = '';
                        for (let i = 0; i < uint8Array.byteLength; i++) {
                            binary += String.fromCharCode(uint8Array[i]);
                        }
                        const base64Data = btoa(binary);

                        const multipartRequestBody =
                            delimiter +
                            'Content-Type: application/json\r\n\r\n' +
                            JSON.stringify(metadata) +
                            delimiter +
                            'Content-Type: application/pdf\r\n' +
                            'Content-Transfer-Encoding: base64\r\n\r\n' +
                            base64Data +
                            close_delim;

                        const response = await fetch('https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart', {
                            method: 'POST',
                            headers: {
                                Authorization: `Bearer ${accessToken}`,
                                'Content-Type': 'multipart/related; boundary="' + boundary + '"',
                            },
                            body: multipartRequestBody,
                        });

                        if (!response.ok) {
                            const errorData = await response.json();
                            throw new Error(errorData.error?.message || '上傳失敗');
                        }

                        setStatus('success');
                        setTimeout(() => setStatus('idle'), 5000);
                        resolve(true);
                    } catch (e: any) {
                        reject(e);
                    }
                };
            });

        } catch (error: any) {
            console.error('Upload Error:', error);
            let msg = '操作失敗';
            if (error.error === 'invalid_request' || (error.message && error.message.includes('400'))) {
                msg = '❌ 授權錯誤 (400)：應用程式狀態不正確。';
                setShowFixGuide(true);
            } else if (error.error === 'popup_closed_by_user') {
                msg = '⚠️ 您關閉了授權視窗。';
            } else if (error.message) {
                msg = error.message;
            }
            setErrorMessage(msg);
            setStatus('error');
        }
    };

    return (
        <div className="flex flex-col items-end">
            <button
                onClick={handleUpload}
                disabled={status === 'uploading'}
                className={`flex items-center space-x-2 font-bold py-2 px-6 rounded-lg transition-all transform hover:scale-105 shadow-md ${
                    status === 'success' ? 'bg-green-100 text-green-700 border border-green-200' : 
                    status === 'error' ? 'bg-red-50 text-red-600 border border-red-200' : 
                    'bg-white text-blue-600 border border-blue-200 hover:bg-blue-50'
                }`}
            >
                {status === 'uploading' ? (
                    <>
                        <svg className="animate-spin h-5 w-5 text-blue-600" viewBox="0 0 24 24">
                            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                        </svg>
                        <span>連接中...</span>
                    </>
                ) : status === 'success' ? (
                    <>
                        <FaCheckCircle className="text-xl" />
                        <span>備份成功！</span>
                    </>
                ) : (
                    <>
                        <FaGoogleDrive className="text-xl text-blue-500" />
                        <span>{t('uploadToDrive')}</span>
                    </>
                )}
            </button>

            {(status === 'error' || showFixGuide) && (
                <div className="mt-3 p-4 bg-white border-2 border-red-500 rounded-xl max-w-[400px] shadow-2xl animate-bounce-subtle text-left">
                    <div className="flex items-center mb-3 text-red-600 font-bold border-b pb-2">
                        <FaExclamationCircle className="mr-2" />
                        <span>解決「已封鎖存取權 (400)」的方法</span>
                    </div>
                    <div className="text-[12px] text-gray-700 space-y-3 leading-relaxed">
                        <p className="font-bold text-red-600">您的應用程式目前為「實際運作中」，這會導致未經驗證的帳號被封鎖。</p>

                        <div className="bg-blue-50 p-3 rounded-lg border border-blue-200">
                            <h4 className="font-bold text-blue-800 flex items-center mb-1">
                                <FaSyncAlt className="mr-1" /> 請執行以下 3 個步驟：
                            </h4>
                            <ol className="list-decimal list-inside space-y-1 font-medium">
                                <li>點擊 Console 畫面的 <span className="bg-blue-600 text-white px-1 rounded">返回測試應用程式</span>。</li>
                                <li>在出現的「測試使用者」區塊點擊 <span className="font-bold text-blue-700">ADD USERS</span>。</li>
                                <li>輸入您的 Email：<strong>cb_esg@carbotec.com.tw</strong>。</li>
                            </ol>
                        </div>

                        <p className="text-gray-500 italic">※ 完成後重新整理網頁再試一次即可成功。</p>

                        <button 
                            onClick={() => { setStatus('idle'); setShowFixGuide(false); }}
                            className="w-full py-1.5 bg-gray-100 hover:bg-gray-200 rounded font-bold text-gray-600 transition-colors"
                        >
                            我了解了，去調整設定
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
