            console.error('Upload Error Details:', error);
            setStatus('error');

            if (error.error === 'access_denied') {
                setErrorType('403');
                setErrorMessage('存取被拒：專案尚未發佈。');
                setShowGuide(true);
            } else if (error.error === 'invalid_request') {
                setErrorType('400');
                setErrorMessage('授權錯誤：網址未授權。');
                setShowGuide(true);
            } else {
                setErrorType('other');
                setErrorMessage('上傳失敗，請稍後再試。');
            }
        }
    };

