                >
                    <FaQuestionCircle />
                </button>
            </div>

            {status === 'error' && !showGuide && (
                <p className="text-[10px] text-red-500 font-medium">{errorMessage}</p>
            )}

            {showGuide && (
                <div className="bg-white border-2 border-blue-600 rounded-xl p-6 shadow-2xl max-w-md text-left animate-fade-in z-50">
                    <h4 className="text-base font-bold text-gray-800 mb-4 flex items-center border-b pb-2">
