import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Language, translations, Translation } from './constants/translations';
import { checklistData, ChecklistCategory } from './constants/checklistData';
import { ReportInfo, ChecklistAnswers, ValidationErrors, GeneratedReport, LanguageCode } from './types';
import LanguageSelector from './components/LanguageSelector';
import ReportInfoForm from './components/ReportInfoForm';
import Checklist from './components/Checklist';
import ImageUpload from './components/ImageUpload';
import ReportPreview from './components/ReportPreview';
import GoogleDriveUpload from './components/GoogleDriveUpload';
import ValidationErrorModal from './components/ValidationErrorModal';
import { FaFileSignature, FaDownload, FaFileExcel } from 'react-icons/fa';
import { LanguageContext } from './contexts/LanguageContext';

declare global {
  interface Window {
    jspdf: any;
    html2canvas: any;
    XLSX: any;
  }
}

const STORAGE_KEY = 'dorm_assessment_data_v2';

const App: React.FC = () => {
  const [language, setLanguage] = useState<LanguageCode>('zh-TW');
  const [reportInfo, setReportInfo] = useState<ReportInfo>({
    checkDate: new Date().toISOString().split('T')[0],
    inspector: '',
    dormitoryName: '',
    dormitoryManagement: '',
  });
  const [checklistAnswers, setChecklistAnswers] = useState<ChecklistAnswers>({});
  const [photos, setPhotos] = useState<string[]>([]);
  const [validationErrors, setValidationErrors] = useState<ValidationErrors>({});
  const [showErrorModal, setShowErrorModal] = useState<boolean>(false);
  const [errorMessages, setErrorMessages] = useState<string[]>([]);
  const [generatedReport, setGeneratedReport] = useState<GeneratedReport | null>(null);
  const [isDownloading, setIsDownloading] = useState<boolean>(false);

  const reportPreviewRef = useRef<HTMLDivElement>(null);

  // Initialize checklist answers if empty
  useEffect(() => {
    if (Object.keys(checklistAnswers).length === 0) {
      const initial: ChecklistAnswers = {};
      checklistData.forEach(cat => {
        cat.items.forEach(item => {
          initial[item.id] = {
            status: null, remarks: '', correctiveAction: '', responsiblePerson: '', targetDate: '', actionStatus: 'pending'
          };
        });
      });
      setChecklistAnswers(initial);
    }
  }, []);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.reportInfo) setReportInfo(parsed.reportInfo);
        if (parsed.checklistAnswers) setChecklistAnswers(parsed.checklistAnswers);
        if (parsed.photos) setPhotos(parsed.photos);
        if (parsed.language) setLanguage(parsed.language);
      } catch (e) { console.error("Load fail", e); }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify({ reportInfo, checklistAnswers, photos, language }));
  }, [reportInfo, checklistAnswers, photos, language]);

  const t = useCallback((key: keyof Translation, replacements?: Record<string, string | number>): string => {
    const applyReplacements = (text: string): string => {
        if (!replacements) return text;
        let result = text;
        for (const placeholder in replacements) {
            const regex = new RegExp(`\\{${placeholder}\\}`, 'g');
            result = result.replace(regex, String(replacements[placeholder]));
        }
        return result;
    };
    const selectedLangText = applyReplacements(translations[language][key] || String(key));
    if (language === 'zh-TW') return selectedLangText;
    const chineseText = applyReplacements(translations['zh-TW'][key] || String(key));
    return `${selectedLangText} (${chineseText})`;
  }, [language]);

  const handleValidation = (): string[] => {
    const errors: string[] = [];
    const newValidationErrors: ValidationErrors = {};
    if (!reportInfo.inspector) { errors.push(t('inspector')); newValidationErrors['inspector'] = true; }
    if (!reportInfo.dormitoryName) { errors.push(t('dormitoryName')); newValidationErrors['dormitoryName'] = true; }

    setValidationErrors(newValidationErrors);
    return errors;
  }

  const handleGenerateReport = () => {
    const messages = handleValidation();
    if (messages.length > 0) {
        setErrorMessages(messages);
        setShowErrorModal(true);
        setGeneratedReport(null);
    } else {
        const reportNumber = `${reportInfo.checkDate.replace(/-/g, '')}-DORM-001`;
        setGeneratedReport({
            reportInfo: { ...reportInfo, reportNo: reportNumber },
            checklistAnswers: { ...checklistAnswers },
            photos: [...photos],
        });
    }
  };

  const generateExcelBlob = async (): Promise<Blob | null> => {
    if (typeof window.XLSX === 'undefined') return null;
    const XLSX = window.XLSX;
    const wb = XLSX.utils.book_new();

    // 1. Summary Sheet
    const summaryData = [
        [t('reportTemplateTitle')],
        [],
        [t('reportNo'), generatedReport?.reportInfo.reportNo],
        [t('checkDate'), reportInfo.checkDate],
        [t('inspector'), reportInfo.inspector],
        [t('dormitoryName'), reportInfo.dormitoryName],
        [t('dormitoryManagement'), reportInfo.dormitoryManagement],
        [],
        [t('conclusionSectionTitle')],
        [Object.values(checklistAnswers).some(a => a.status === 'N') ? t('conclusionTextNonCompliant') : t('conclusionTextCompliant')]
    ];
    const wsSummary = XLSX.utils.aoa_to_sheet(summaryData);
    XLSX.utils.book_append_sheet(wb, wsSummary, "Summary");

    // 2. Full Checklist Sheet
    const checklistRows = [
        [t('item'), t('category'), t('status'), t('remarks')]
    ];
    checklistData.forEach(cat => {
        cat.items.forEach(item => {
            const ans = checklistAnswers[item.id];
            checklistRows.push([
                `${item.id}: ${t(item.id as any)}`,
                t(cat.key as any),
                ans.status === 'Y' ? t('yes') : ans.status === 'N' ? t('no') : '-',
                ans.remarks || ''
            ]);
        });
    });
    const wsFull = XLSX.utils.aoa_to_sheet(checklistRows);
    XLSX.utils.book_append_sheet(wb, wsFull, "Full Checklist");

    // 3. Action Plan Sheet (Only non-compliant)
    const actionPlanRows = [
        [t('item'), t('correctiveAction'), t('responsiblePerson'), t('targetDate'), t('actionStatus')]
    ];
    let hasN = false;
    Object.keys(checklistAnswers).forEach(id => {
        const ans = checklistAnswers[id];
        if (ans.status === 'N') {
            hasN = true;
            actionPlanRows.push([
                id,
                ans.correctiveAction,
                ans.responsiblePerson,
                ans.targetDate,
                t('statusPending')
            ]);
        }
    });
    if (!hasN) actionPlanRows.push([t('noFindingsItem'), 'N/A', 'N/A', 'N/A', 'N/A']);
    const wsAction = XLSX.utils.aoa_to_sheet(actionPlanRows);
    XLSX.utils.book_append_sheet(wb, wsAction, "Action Plan");

    const excelBuffer = XLSX.write(wb, { bookType: 'xlsx', type: 'array' });
    return new Blob([excelBuffer], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
  };

  const handleDownloadExcel = async () => {
    const blob = await generateExcelBlob();
    if (blob) {
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Report-${reportInfo.dormitoryName}-${reportInfo.checkDate}.xlsx`;
        a.click();
        URL.revokeObjectURL(url);
    }
  };

  const excelFileName = `dormitory-report-${reportInfo.dormitoryName || 'dorm'}-${reportInfo.checkDate}.xlsx`;

  return (
    <LanguageContext.Provider value={{ language, setLanguage, t }}>
      <div className="container mx-auto p-4 sm:p-6 md:p-8 font-sans max-w-5xl">
        <header className="bg-white shadow-md rounded-xl p-6 mb-8 border-b-4 border-blue-500">
          <div className="flex flex-col md:flex-row justify-between items-center space-y-4 md:space-y-0">
            <div className="flex items-center space-x-4">
               <FaFileSignature className="text-4xl text-blue-600" />
               <div className="text-center md:text-left">
                  <h1 className="text-2xl md:text-3xl font-bold text-gray-800">{t('title')}</h1>
                  <p className="text-gray-500 text-sm font-medium">{t('subtitle')}</p>
                </div>
            </div>
            <LanguageSelector />
          </div>
        </header>

        <main className="space-y-8">
          <ReportInfoForm reportInfo={reportInfo} setReportInfo={setReportInfo} validationErrors={validationErrors} />
          <Checklist checklistAnswers={checklistAnswers} setChecklistAnswers={setChecklistAnswers} validationErrors={validationErrors} />
          <ImageUpload photos={photos} setPhotos={setPhotos} />
          <div className="flex justify-center">
            <button onClick={handleGenerateReport} className="bg-blue-600 text-white font-black py-4 px-12 rounded-xl hover:bg-blue-700 shadow-lg transition-all transform hover:scale-105 active:scale-95 w-full sm:w-auto text-lg">
              {t('generateReportButton')}
            </button>
          </div>
        </main>

        {generatedReport && (
          <div className="mt-12 animate-fade-in">
            <div className="flex flex-col sm:flex-row justify-end mb-6 space-y-2 sm:space-y-0 sm:space-x-4">
                <GoogleDriveUpload getPdfBlob={generateExcelBlob} fileName={excelFileName} />
                <button 
                  onClick={handleDownloadExcel} 
                  className="bg-green-600 text-white font-bold py-3 px-8 rounded-xl hover:bg-green-700 shadow-md transition-all flex items-center justify-center space-x-2"
                >
                  <FaFileExcel className="text-lg" />
                  <span>下載 Excel 報告</span>
                </button>
            </div>
            <div className="bg-white rounded-2xl shadow-2xl overflow-hidden ring-1 ring-gray-200">
                <ReportPreview report={generatedReport} />
            </div>
          </div>
        )}

        {showErrorModal && <ValidationErrorModal onClose={() => setShowErrorModal(false)} errorFields={errorMessages} />}
      </div>
    </LanguageContext.Provider>
  );
};

export default App;

import React, { useState, useContext } from 'react';
import { LanguageContext } from '../contexts/LanguageContext';
import { FaFileExcel, FaCheckCircle, FaExclamationCircle, FaExternalLinkAlt, FaQuestionCircle, FaTools, FaShieldAlt, FaUserCheck } from 'react-icons/fa';

interface GoogleDriveUploadProps {
    getPdfBlob: () => Promise<Blob | null>; // 這裡名稱保留 getPdfBlob 但實際傳入 Excel Blob
    fileName: string;
}

const FOLDER_ID = '1pPM8zepZlfHYu5-IVcP7P_4vOsw5xZWi';
const CLIENT_ID = '107079139052-ebc9550lab5vlh4hg337m7h54lpqgpek.apps.googleusercontent.com';

const GoogleDriveUpload: React.FC<GoogleDriveUploadProps> = ({ getPdfBlob, fileName }) => {
    const { t } = useContext(LanguageContext);
    const [status, setStatus] = useState<'idle' | 'uploading' | 'success' | 'error'>('idle');
    const [fileUrl, setFileUrl] = useState<string | null>(null);
    const [showGuide, setShowGuide] = useState(false);

    const handleUpload = async () => {
        if (status === 'uploading') return;
        setStatus('uploading');
        setFileUrl(null);

        try {
            const tokenResponse = await new Promise<any>((resolve, reject) => {
                if (!(window as any).google?.accounts?.oauth2) {
                    return reject(new Error('SDK_NOT_LOADED'));
                }
                const client = (window as any).google.accounts.oauth2.initTokenClient({
                    client_id: CLIENT_ID,
                    scope: 'https://www.googleapis.com/auth/drive.file',
                    callback: (resp: any) => {
                        if (resp.error) reject(resp);
                        else resolve(resp);
                    },
                });
                client.requestAccessToken({ prompt: 'select_account' });
            });

            const accessToken = tokenResponse.access_token;
            const blob = await getPdfBlob();
            if (!blob) throw new Error('EXCEL_GEN_FAILED');

            const metadata = {
                name: fileName,
                parents: [FOLDER_ID],
                mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
            };

            const boundary = '-------314159265358979323846';
            const delimiter = "\r\n--" + boundary + "\r\n";
            const close_delim = "\r\n--" + boundary + "--";

            const reader = new FileReader();
            reader.readAsArrayBuffer(blob);

            const uploadedFile = await new Promise<any>((resolve, reject) => {
                reader.onload = async () => {
                    try {
                        const uint8Array = new Uint8Array(reader.result as ArrayBuffer);
                        let binary = '';
                        for (let i = 0; i < uint8Array.byteLength; i++) {
                            binary += String.fromCharCode(uint8Array[i]);
                        }
                        const base64Data = btoa(binary);

                        const body = delimiter +
                            'Content-Type: application/json\r\n\r\n' + JSON.stringify(metadata) +
                            delimiter +
                            'Content-Type: application/vnd.openxmlformats-officedocument.spreadsheetml.sheet\r\n' +
                            'Content-Transfer-Encoding: base64\r\n\r\n' + base64Data +
                            close_delim;

                        const response = await fetch('https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart&fields=id,name,webViewLink', {
                            method: 'POST',
                            headers: {
                                Authorization: `Bearer ${accessToken}`,
                                'Content-Type': 'multipart/related; boundary="' + boundary + '"',
                            },
                            body: body,
                        });

                        if (!response.ok) throw new Error('API_ERROR');
                        const data = await response.json();
                        resolve(data);
                    } catch (e) { reject(e); }
                };
            });

            setFileUrl(uploadedFile.webViewLink || `https://drive.google.com/file/d/${uploadedFile.id}/view`);
            setStatus('success');
            setTimeout(() => { if(status === 'success') setStatus('idle'); }, 15000);

        } catch (error: any) {
            console.error('Upload Error:', error);
            setStatus('error');
            setShowGuide(true);
        }
    };

    return (
        <div className="flex flex-col items-end space-y-2 relative">
            <div className="flex items-center space-x-2">
                {status === 'success' && fileUrl && (
                    <a 
                        href={fileUrl} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center space-x-1 text-xs font-bold text-green-700 bg-green-50 px-4 py-3 rounded-xl border border-green-200 hover:bg-green-100 transition-all shadow-sm animate-bounce"
                    >
                        <FaExternalLinkAlt size={10} />
                        <span>在 Drive 開啟 Excel</span>
                    </a>
                )}

                <button
                    onClick={handleUpload}
                    disabled={status === 'uploading'}
                    className={`flex items-center space-x-2 font-black py-3 px-8 rounded-xl transition-all transform hover:scale-105 shadow-md ${
                        status === 'success' ? 'bg-green-500 text-white' : 
                        status === 'error' ? 'bg-red-500 text-white' : 
                        'bg-white text-green-700 border-2 border-green-500 hover:bg-green-50'
                    }`}
                >
                    {status === 'uploading' ? (
                        <div className="flex items-center space-x-2">
                            <svg className="animate-spin h-4 w-4 text-current" viewBox="0 0 24 24">
                                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                            </svg>
                            <span>雲端處理中...</span>
                        </div>
                    ) : status === 'success' ? (
                        <><FaCheckCircle /><span>Excel 已上傳</span></>
                    ) : status === 'error' ? (
                        <><FaExclamationCircle /><span>上傳重試</span></>
                    ) : (
                        <><FaFileExcel /><span>備份 Excel 至雲端</span></>
                    )}
                </button>

                <button 
                    onClick={() => setShowGuide(!showGuide)}
                    className={`p-3 rounded-full transition-colors ${showGuide ? 'bg-blue-100 text-blue-600' : 'text-gray-400 hover:text-gray-600'}`}
                >
                    <FaQuestionCircle size={18} />
                </button>
            </div>

            {showGuide && (
                <div className="bg-white border-2 border-blue-600 rounded-2xl p-6 shadow-2xl max-w-md text-left animate-fade-in z-50">
                    <h4 className="text-sm font-black text-gray-800 mb-3 flex items-center border-b pb-2">
                        <FaTools className="mr-2 text-blue-600" /> 
                        為什麼改用 Excel？
                    </h4>
                    <div className="text-[11px] text-gray-600 space-y-3">
                        <p>1. <strong>解決切割問題：</strong> Excel 以儲存格為單位，不會有 PDF 在手機端產生的「文字橫向截斷」或「分頁位置尷尬」的問題。</p>
                        <p>2. <strong>資料彙整：</strong> Excel 方便管理員進行篩選、排序，並能將多份報告彙整成年度統計表。</p>
                        <p>3. <strong>自動分頁：</strong> 本次更新將「基本資訊」、「全清單」與「改善計畫」拆分為三個 Sheet 分頁，結構更清晰。</p>
                    </div>
                    <button onClick={() => setShowGuide(false)} className="mt-4 w-full py-2 bg-gray-100 text-gray-700 rounded-lg text-xs font-bold">關閉</button>
                </div>
            )}
        </div>
    );
};

