import React, { useContext, useRef, useState } from 'react';
import { LanguageContext } from '../contexts/LanguageContext';
import { FaSave, FaUpload, FaTrashAlt, FaInfoCircle, FaCloudUploadAlt, FaCheckCircle, FaExclamationCircle } from 'react-icons/fa';
import { ReportInfo, ChecklistAnswers } from '../types';

interface DataManagementProps {
    reportInfo: ReportInfo;
    checklistAnswers: ChecklistAnswers;
    photos: string[];
    onRestore: (data: { reportInfo: ReportInfo, checklistAnswers: ChecklistAnswers, photos: string[] }) => void;
    onClear: () => void;
}

const FOLDER_ID = '11_Bdd1tKHTAR-CJ79o-0ShE5VLB3objg';
const CLIENT_ID = '107079139052-ebc9550lab5vlh4hg337m7h54lpqgpek.apps.googleusercontent.com';

const DataManagement: React.FC<DataManagementProps> = ({ reportInfo, checklistAnswers, photos, onRestore, onClear }) => {
    const { t } = useContext(LanguageContext);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [cloudStatus, setCloudStatus] = useState<'idle' | 'uploading' | 'success' | 'error'>('idle');

    const handleExport = () => {
        const data = {
            reportInfo,
            checklistAnswers,
            photos,
            exportedAt: new Date().toISOString()
        };
        const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        const fileName = `dorm-data-${reportInfo.dormitoryName || 'backup'}-${new Date().toISOString().split('T')[0]}.json`;
        link.download = fileName;
        link.click();
        URL.revokeObjectURL(url);
    };

    const handleCloudBackup = async () => {
        if (cloudStatus === 'uploading') return;
        setCloudStatus('uploading');

        try {
            const tokenResponse = await new Promise<any>((resolve, reject) => {
                if (!(window as any).google?.accounts?.oauth2) {
                    return reject(new Error('SDK_NOT_LOADED'));
                }
                const client = (window as any).google.accounts.oauth2.initTokenClient({
                    client_id: CLIENT_ID,
                    scope: 'https://www.googleapis.com/auth/drive.file',
                    callback: (resp: any) => {
                        if (resp.error) reject(resp);
                        else resolve(resp);
                    },
                });
                client.requestAccessToken({ prompt: 'select_account' });
            });

            const accessToken = tokenResponse.access_token;
            const data = {
                reportInfo,
                checklistAnswers,
                photos,
                exportedAt: new Date().toISOString()
            };
            const jsonString = JSON.stringify(data, null, 2);
            const fileName = `data-backup-${reportInfo.dormitoryName || 'unknown'}-${new Date().toISOString().split('T')[0]}.json`;

            const metadata = {
                name: fileName,
                parents: [FOLDER_ID],
                mimeType: 'application/json',
            };

            const boundary = '-------314159265358979323846';
            const delimiter = "\r\n--" + boundary + "\r\n";
            const close_delim = "\r\n--" + boundary + "--";

            const body = delimiter +
                'Content-Type: application/json\r\n\r\n' + JSON.stringify(metadata) +
                delimiter +
                'Content-Type: application/json\r\n' +
                'Content-Transfer-Encoding: base64\r\n\r\n' + btoa(unescape(encodeURIComponent(jsonString))) +
                close_delim;

            const response = await fetch('https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart&fields=id,name', {
                method: 'POST',
                headers: {
                    Authorization: `Bearer ${accessToken}`,
                    'Content-Type': 'multipart/related; boundary="' + boundary + '"',
                },
                body: body,
            });

            if (!response.ok) throw new Error('API_ERROR');
            setCloudStatus('success');
            setTimeout(() => setCloudStatus('idle'), 5000);
        } catch (error) {
            console.error('Cloud Backup Error:', error);
            setCloudStatus('error');
            setTimeout(() => setCloudStatus('idle'), 5000);
        }
    };

    const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const data = JSON.parse(event.target?.result as string);
                if (data.reportInfo && data.checklistAnswers) {
                    onRestore({
                        reportInfo: data.reportInfo,
                        checklistAnswers: data.checklistAnswers,
                        photos: data.photos || []
                    });
                } else {
                    throw new Error('Invalid format');
                }
            } catch (err) {
                alert('導入失敗，請確保檔案格式正確。');
            }
        };
        reader.readAsText(file);
        if (fileInputRef.current) fileInputRef.current.value = '';
    };

    const confirmClear = () => {
        if (window.confirm('確定要清空所有已填寫的內容嗎？此動作無法復原。')) {
            onClear();
        }
    };

    return (
        <div className="bg-white shadow-md rounded-xl p-6 border-l-4 border-blue-500 mb-8">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-4 space-y-4 md:space-y-0">
                <div>
                    <h2 className="text-xl font-bold text-gray-800 flex items-center">
                        <FaSave className="mr-2 text-blue-600" />
                        資料管理與雲端備份
                    </h2>
                    <p className="text-xs text-gray-500 mt-1 flex items-center">
                        <FaInfoCircle className="mr-1" />
                        填寫完的表單資料（JSON）也可以直接備份至 Google 雲端硬碟。
                    </p>
                </div>

                <div className="flex flex-wrap gap-2">
                    <button
                        onClick={handleCloudBackup}
                        disabled={cloudStatus === 'uploading'}
                        className={`px-4 py-2 rounded-lg text-sm font-bold flex items-center transition-all shadow-sm ${
                            cloudStatus === 'success' ? 'bg-green-500 text-white' : 
                            cloudStatus === 'error' ? 'bg-red-500 text-white' : 
                            'bg-blue-50 text-blue-700 border border-blue-200 hover:bg-blue-100'
                        }`}
                    >
                        {cloudStatus === 'uploading' ? '上傳中...' : cloudStatus === 'success' ? <><FaCheckCircle className="mr-2"/>備份成功</> : <><FaCloudUploadAlt className="mr-2"/>雲端備份 (JSON)</>}
                    </button>

                    <button
                        onClick={handleExport}
                        className="bg-white hover:bg-gray-50 text-gray-700 px-4 py-2 rounded-lg text-sm font-bold flex items-center transition-colors border border-gray-300 shadow-sm"
                    >
                        <FaSave className="mr-2 text-blue-500" />
                        本地匯出
                    </button>

                    <button
                        onClick={() => fileInputRef.current?.click()}
                        className="bg-gray-100 hover:bg-gray-200 text-gray-700 px-4 py-2 rounded-lg text-sm font-bold flex items-center transition-colors border border-gray-300"
                    >
                        <FaUpload className="mr-2" />
                        導入備份
                    </button>

                    <button
                        onClick={confirmClear}
                        className="bg-red-50 hover:bg-red-100 text-red-600 px-4 py-2 rounded-lg text-sm font-bold flex items-center transition-colors border border-red-200"
                    >
                        <FaTrashAlt className="mr-2" />
                        清空
                    </button>
                </div>
            </div>
            <input type="file" ref={fileInputRef} onChange={handleImport} accept=".json" className="hidden" />
        </div>
    );
};

export default DataManagement;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Language, translations, Translation } from './constants/translations';
import { checklistData, ChecklistCategory } from './constants/checklistData';
import { ReportInfo, ChecklistAnswers, ValidationErrors, GeneratedReport, LanguageCode, ChecklistItemAnswer } from './types';
import LanguageSelector from './components/LanguageSelector';
import ReportInfoForm from './components/ReportInfoForm';
import Checklist from './components/Checklist';
import ImageUpload from './components/ImageUpload';
import ReportPreview from './components/ReportPreview';
import GoogleDriveUpload from './components/GoogleDriveUpload';
import ValidationErrorModal from './components/ValidationErrorModal';
import { FaFileSignature, FaFilePdf, FaFileExcel, FaDownload } from 'react-icons/fa';
import { LanguageContext } from './contexts/LanguageContext';

declare global {
  interface Window {
    jspdf: any;
    html2canvas: any;
    XLSX: any;
    google: any;
  }
}

const STORAGE_KEY = 'dorm_assessment_data_v2';

const App: React.FC = () => {
  const [language, setLanguage] = useState<LanguageCode>('zh-TW');

  const createInitialAnswers = (): ChecklistAnswers => {
    const initial: ChecklistAnswers = {};
    checklistData.forEach(cat => {
      cat.items.forEach(item => {
        initial[item.id] = {
          status: null, 
          remarks: '', 
          correctiveAction: '', 
          responsiblePerson: '', 
          targetDate: '', 
          actionStatus: 'pending'
        };
      });
    });
    return initial;
  };

  const [reportInfo, setReportInfo] = useState<ReportInfo>({
    checkDate: new Date().toISOString().split('T')[0],
    inspector: '',
    dormitoryName: '',
    dormitoryManagement: '',
  });
  const [checklistAnswers, setChecklistAnswers] = useState<ChecklistAnswers>(createInitialAnswers);
  const [photos, setPhotos] = useState<string[]>([]);
  const [validationErrors, setValidationErrors] = useState<ValidationErrors>({});
  const [showErrorModal, setShowErrorModal] = useState<boolean>(false);
  const [errorMessages, setErrorMessages] = useState<string[]>([]);
  const [generatedReport, setGeneratedReport] = useState<GeneratedReport | null>(null);

  const reportPreviewRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.reportInfo) setReportInfo(parsed.reportInfo);
        if (parsed.checklistAnswers) {
          setChecklistAnswers(prev => ({ ...prev, ...parsed.checklistAnswers }));
        }
        if (parsed.photos) setPhotos(parsed.photos);
        if (parsed.language) setLanguage(parsed.language);
      } catch (e) { console.error("Load fail", e); }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify({ reportInfo, checklistAnswers, photos, language }));
  }, [reportInfo, checklistAnswers, photos, language]);

  const t = useCallback((key: keyof Translation, replacements?: Record<string, string | number>): string => {
    const applyReplacements = (text: string): string => {
        if (!replacements) return text;
        let result = text;
        for (const placeholder in replacements) {
            const regex = new RegExp(`\\{${placeholder}\\}`, 'g');
            result = result.replace(regex, String(replacements[placeholder]));
        }
        return result;
    };
    const selectedLangText = applyReplacements(translations[language][key] || String(key));
    if (language === 'zh-TW') return selectedLangText;
    const chineseText = applyReplacements(translations['zh-TW'][key] || String(key));
    return `${selectedLangText} (${chineseText})`;
  }, [language]);

  const handleValidation = (): string[] => {
    const errors: string[] = [];
    const newValidationErrors: ValidationErrors = {};
    if (!reportInfo.inspector) { errors.push(t('inspector')); newValidationErrors['inspector'] = true; }
    if (!reportInfo.dormitoryName) { errors.push(t('dormitoryName')); newValidationErrors['dormitoryName'] = true; }
    setValidationErrors(newValidationErrors);
    return errors;
  }

  const handleGenerateReport = () => {
    const messages = handleValidation();
    if (messages.length > 0) {
        setErrorMessages(messages);
        setShowErrorModal(true);
        setGeneratedReport(null);
    } else {
        const reportNumber = `${reportInfo.checkDate.replace(/-/g, '')}-DORM-001`;
        setGeneratedReport({
            reportInfo: { ...reportInfo, reportNo: reportNumber },
            checklistAnswers: { ...checklistAnswers },
            photos: [...photos],
        });
    }
  };

  const generateExcelBlob = async (): Promise<Blob | null> => {
    if (typeof window.XLSX === 'undefined') return null;
    const XLSX = window.XLSX;
    const wb = XLSX.utils.book_new();

    const summaryData = [
        [t('reportTemplateTitle')],
        [],
        [t('reportNo'), generatedReport?.reportInfo.reportNo],
        [t('checkDate'), reportInfo.checkDate],
        [t('inspector'), reportInfo.inspector],
        [t('dormitoryName'), reportInfo.dormitoryName],
        [t('dormitoryManagement'), reportInfo.dormitoryManagement],
        [],
        [t('conclusionSectionTitle')],
        [(Object.values(checklistAnswers) as ChecklistItemAnswer[]).some(a => a.status === 'N') ? t('conclusionTextNonCompliant') : t('conclusionTextCompliant')]
    ];
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(summaryData), "Summary");

    const checklistRows = [[t('item'), t('category'), t('status'), t('remarks')]];
    checklistData.forEach(cat => {
        cat.items.forEach(item => {
            const ans = checklistAnswers[item.id];
            checklistRows.push([
                `${item.id}: ${t(item.id as any)}`,
                t(cat.key as any),
                ans ? (ans.status === 'Y' ? t('yes') : ans.status === 'N' ? t('no') : '-') : '-',
                ans?.remarks || ''
            ]);
        });
    });
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(checklistRows), "Full Checklist");

    const actionRows = [[t('item'), t('correctiveAction'), t('responsiblePerson'), t('targetDate'), t('actionStatus')]];
    let hasN = false;
    Object.keys(checklistAnswers).forEach(id => {
        const ans = checklistAnswers[id];
        if (ans && ans.status === 'N') {
            hasN = true;
            actionRows.push([id, ans.correctiveAction, ans.responsiblePerson, ans.targetDate, t('statusPending')]);
        }
    });
    if (!hasN) actionRows.push([t('noFindingsItem'), 'N/A', 'N/A', 'N/A', 'N/A']);
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(actionRows), "Action Plan");

    const excelBuffer = XLSX.write(wb, { bookType: 'xlsx', type: 'array' });
    return new Blob([excelBuffer], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
  };

  const generatePdfBlob = async (): Promise<Blob | null> => {
    const reportElement = document.getElementById('full-report-container');
    if (!reportElement || !window.html2canvas || !window.jspdf) return null;

    try {
        const canvas = await window.html2canvas(reportElement, {
            scale: 2,
            useCORS: true,
            logging: false,
            windowWidth: reportElement.scrollWidth,
            windowHeight: reportElement.scrollHeight
        });

        const imgData = canvas.toDataURL('image/jpeg', 0.95);
        const pdf = new window.jspdf.jsPDF('p', 'mm', 'a4');
        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = pdf.internal.pageSize.getHeight();
        const imgWidth = pdfWidth;
        const imgHeight = (canvas.height * imgWidth) / canvas.width;

        let heightLeft = imgHeight;
        let position = 0;

        pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
        heightLeft -= pdfHeight;

        while (heightLeft >= 0) {
            position = heightLeft - imgHeight;
            pdf.addPage();
            pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
            heightLeft -= pdfHeight;
        }

        return pdf.output('blob');
    } catch (error) {
        console.error('PDF generation error:', error);
        return null;
    }
  };

  const handleDownloadExcel = async () => {
    const blob = await generateExcelBlob();
    if (blob) {
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Report-${reportInfo.dormitoryName}-${reportInfo.checkDate}.xlsx`;
        a.click();
        URL.revokeObjectURL(url);
    }
  };

  const handleDownloadPdf = async () => {
    const blob = await generatePdfBlob();
    if (blob) {
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Report-${reportInfo.dormitoryName}-${reportInfo.checkDate}.pdf`;
        a.click();
        URL.revokeObjectURL(url);
    }
  };

  return (
    <LanguageContext.Provider value={{ language, setLanguage, t }}>
      <div className="container mx-auto p-4 sm:p-6 md:p-8 font-sans max-w-5xl">
        <header className="bg-white shadow-md rounded-xl p-6 mb-8 border-b-4 border-blue-500">
          <div className="flex flex-col md:flex-row justify-between items-center space-y-4 md:space-y-0">
            <div className="flex items-center space-x-4">
               <FaFileSignature className="text-4xl text-blue-600" />
               <div className="text-center md:text-left">
                  <h1 className="text-2xl md:text-3xl font-bold text-gray-800">{t('title')}</h1>
                  <p className="text-gray-500 text-sm font-medium">{t('subtitle')}</p>
                </div>
            </div>
            <LanguageSelector />
          </div>
        </header>

        <main className="space-y-8">
          <ReportInfoForm reportInfo={reportInfo} setReportInfo={setReportInfo} validationErrors={validationErrors} />
          <Checklist checklistAnswers={checklistAnswers} setChecklistAnswers={setChecklistAnswers} validationErrors={validationErrors} />
          <ImageUpload photos={photos} setPhotos={setPhotos} />
          <div className="flex justify-center">
            <button onClick={handleGenerateReport} className="bg-blue-600 text-white font-black py-4 px-12 rounded-xl hover:bg-blue-700 shadow-lg transition-all transform hover:scale-105 active:scale-95 w-full sm:w-auto text-lg">
              {t('generateReportButton')}
            </button>
          </div>
        </main>

        {generatedReport && (
          <div className="mt-12 animate-fade-in">
            <div className="flex flex-col sm:flex-row justify-end mb-6 space-y-2 sm:space-y-0 sm:space-x-4">
                <GoogleDriveUpload 
                  getPdfBlob={generatePdfBlob} 
                  getExcelBlob={generateExcelBlob}
                  baseFileName={`report-${reportInfo.dormitoryName}-${reportInfo.checkDate}`} 
                />
                <button 
                  onClick={handleDownloadPdf} 
                  className="bg-red-600 text-white font-bold py-3 px-6 rounded-xl hover:bg-red-700 shadow-md transition-all flex items-center justify-center space-x-2"
                >
                  <FaFilePdf className="text-lg" />
                  <span>下載 PDF</span>
                </button>
                <button 
                  onClick={handleDownloadExcel} 
                  className="bg-green-600 text-white font-bold py-3 px-6 rounded-xl hover:bg-green-700 shadow-md transition-all flex items-center justify-center space-x-2"
                >
                  <FaFileExcel className="text-lg" />
                  <span>下載 Excel</span>
                </button>
            </div>
            <div className="bg-white rounded-2xl shadow-2xl overflow-hidden ring-1 ring-gray-200">
                <ReportPreview report={generatedReport} />
            </div>
          </div>
        )}

        {showErrorModal && <ValidationErrorModal onClose={() => setShowErrorModal(false)} errorFields={errorMessages} />}
      </div>
    </LanguageContext.Provider>
  );
};

export default App;

import React, { useState, useContext } from 'react';
import { LanguageContext } from '../contexts/LanguageContext';
import { FaFilePdf, FaFileExcel, FaCheckCircle, FaExclamationCircle, FaExternalLinkAlt, FaQuestionCircle, FaCloudUploadAlt, FaCaretDown } from 'react-icons/fa';

interface GoogleDriveUploadProps {
    getPdfBlob: () => Promise<Blob | null>;
    getExcelBlob: () => Promise<Blob | null>;
    baseFileName: string;
}

/** 
 * 注意：更換帳號後，請務必執行以下步驟：
 * 1. FOLDER_ID: 已更新為您的新資料夾 ID。
 * 2. CLIENT_ID: 請填入您在新帳號 Google Cloud Console 申請的「OAuth 2.0 用戶端 ID」。
 * 3. 測試使用者: 務必在 OAuth 同意畫面中將您的 Email 加入「測試使用者」名單。
 */
const FOLDER_ID = '11_Bdd1tKHTAR-CJ79o-0ShE5VLB3objg';
const CLIENT_ID = '107079139052-ebc9550lab5vlh4hg337m7h54lpqgpek.apps.googleusercontent.com'; // 請替換為新帳號的 Client ID

const GoogleDriveUpload: React.FC<GoogleDriveUploadProps> = ({ getPdfBlob, getExcelBlob, baseFileName }) => {
    const { t } = useContext(LanguageContext);
    const [status, setStatus] = useState<'idle' | 'uploading' | 'success' | 'error'>('idle');
    const [fileUrl, setFileUrl] = useState<string | null>(null);
    const [showGuide, setShowGuide] = useState(false);
    const [uploadFormat, setUploadFormat] = useState<'pdf' | 'excel'>('pdf');
    const [showDropdown, setShowDropdown] = useState(false);

    const handleUpload = async () => {
        if (status === 'uploading') return;
        setStatus('uploading');
        setFileUrl(null);
        setShowDropdown(false);

        try {
            const tokenResponse = await new Promise<any>((resolve, reject) => {
                if (!(window as any).google?.accounts?.oauth2) {
                    return reject(new Error('SDK_NOT_LOADED'));
                }
                const client = (window as any).google.accounts.oauth2.initTokenClient({
                    client_id: CLIENT_ID,
                    scope: 'https://www.googleapis.com/auth/drive.file',
                    callback: (resp: any) => {
                        if (resp.error) reject(resp);
                        else resolve(resp);
                    },
                });
                client.requestAccessToken({ prompt: 'select_account' });
            });

            const accessToken = tokenResponse.access_token;

            let blob: Blob | null = null;
            let mimeType = '';
            let finalFileName = '';

            if (uploadFormat === 'pdf') {
                blob = await getPdfBlob();
                mimeType = 'application/pdf';
                finalFileName = `${baseFileName}.pdf`;
            } else {
                blob = await getExcelBlob();
                mimeType = 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet';
                finalFileName = `${baseFileName}.xlsx`;
            }

            if (!blob) throw new Error('BLOB_GEN_FAILED');

            const metadata = {
                name: finalFileName,
                parents: [FOLDER_ID],
                mimeType: mimeType,
            };

            const boundary = '-------314159265358979323846';
            const delimiter = "\r\n--" + boundary + "\r\n";
            const close_delim = "\r\n--" + boundary + "--";

            const reader = new FileReader();
            reader.readAsArrayBuffer(blob);

            const uploadedFile = await new Promise<any>((resolve, reject) => {
                reader.onload = async () => {
                    try {
                        const uint8Array = new Uint8Array(reader.result as ArrayBuffer);
                        let binary = '';
                        for (let i = 0; i < uint8Array.byteLength; i++) {
                            binary += String.fromCharCode(uint8Array[i]);
                        }
                        const base64Data = btoa(binary);

                        const body = delimiter +
                            'Content-Type: application/json\r\n\r\n' + JSON.stringify(metadata) +
                            delimiter +
                            'Content-Type: ' + mimeType + '\r\n' +
                            'Content-Transfer-Encoding: base64\r\n\r\n' + base64Data +
                            close_delim;

                        const response = await fetch('https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart&fields=id,name,webViewLink', {
                            method: 'POST',
                            headers: {
                                Authorization: `Bearer ${accessToken}`,
                                'Content-Type': 'multipart/related; boundary="' + boundary + '"',
                            },
                            body: body,
                        });

                        if (!response.ok) throw new Error('API_ERROR');
                        const data = await response.json();
                        resolve(data);
                    } catch (e) { reject(e); }
                };
            });

            setFileUrl(uploadedFile.webViewLink || `https://drive.google.com/file/d/${uploadedFile.id}/view`);
            setStatus('success');
            setTimeout(() => { if(status === 'success') setStatus('idle'); }, 15000);

        } catch (error: any) {
            console.error('Upload Error:', error);
            setStatus('error');
        }
    };

    return (
        <div className="flex flex-col items-end space-y-2 relative">
            <div className="flex items-center space-x-2">
                {status === 'success' && fileUrl && (
                    <a 
                        href={fileUrl} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center space-x-1 text-xs font-bold text-blue-700 bg-blue-50 px-4 py-3 rounded-xl border border-blue-200 hover:bg-blue-100 transition-all shadow-sm animate-bounce"
                    >
                        <FaExternalLinkAlt size={10} />
                        <span>開啟備份檔案</span>
                    </a>
                )}

                <div className="relative flex items-stretch">
                    <button
                        onClick={() => setShowDropdown(!showDropdown)}
