        if (status === 'uploading') return;

        // 1. 檢查是否仍在使用我的範例 ID
        if (CLIENT_ID.startsWith('211134551544')) {
            alert(`⚠️ 偵測到您仍在使用範例 ID。\n\n請將程式碼中的 CLIENT_ID 替換為您剛才在 Google Cloud Console 畫面中看到的「用戶端 ID」。`);
            return;
        }

