            }

            alert(`${errorMsg}\n\n(詳細代碼: ${err.error || 'unknown'})`);
        }
    };

    return (
        <div className="flex flex-col items-end space-y-2 relative">
            <div className="flex items-center space-x-2">
                {status === 'success' && fileUrl && (
                    <a 
