        const contentWidth = pdfWidth - (marginX * 2); // 190mm

        const addSectionToPdf = async (element: HTMLElement, addNewPageBefore: boolean = false) => {
            const canvas = await window.html2canvas(element, {
                scale: 2,
                useCORS: true,
                logging: false,
                width: 1000,
                windowWidth: 1000,
                backgroundColor: '#ffffff'
